// Wait for 1st request (failure)
console.log('Waiting for 1st request...');
await waitForNextRequest();

console.log('Polling for 1st attempt failure in Svix API...');
let attempts1 = [];
while (true) {
    const res = await svix.messageAttempt.listByMsg(svixApp.id, msg.id);
    attempts1 = res.data;
    if (attempts1.length >= 1 && attempts1[0].status === 0) { // 0 usually means fail in Svix API
        console.log('Verified 1st attempt failed.');
        break;
    }
    await new Promise(resolve => setTimeout(resolve, 500));
}

console.log('Resending message after 1st failure...');
await svix.messageAttempt.resend(svixApp.id, msg.id, endpoint.id);

// Wait for 2nd request (failure)
console.log('Waiting for 2nd request...');
await waitForNextRequest();

console.log('Polling for 2nd attempt failure in Svix API...');
let attempts2 = [];
while (true) {
    const res = await svix.messageAttempt.listByMsg(svixApp.id, msg.id);
    attempts2 = res.data;
    if (attempts2.length >= 2 && attempts2[0].status === 0) {
        console.log('Verified 2nd attempt failed.');
        break;
    }
    await new Promise(resolve => setTimeout(resolve, 500));
}

console.log('Resending message after 2nd failure...');
await svix.messageAttempt.resend(svixApp.id, msg.id, endpoint.id);

// Wait for 3rd request (success)
