let attempts2 = [];
while (true) {
    try {
        const res = await svix.messageAttempt.listByMsg(svixApp.id, msg.id);
        attempts2 = res.data;
        if (attempts2.length >= 2) {
            if (attempts2[0].status === 2) {
                console.log('Verified 2nd attempt failed.');
                break;
            }
        }
    } catch (e) {}
    await new Promise(resolve => setTimeout(resolve, 500));
}

